{"name":"./src/index.ts","startLine":1,"endLine":16,"content":"import { Ok, type Result } from "./result";

const RETURN = "return ";
const T = "tokens";
const RETURN_ZERO = ";" + RETURN + "0;";

function isWhitespace(char: string | undefined): boolean {
  return char === " " || char === "\t" || char === "\n" || char === "\r" || char === undefined;
}

export enum CompileError {
  NotImplemented,
}

export function compile(input: string): Result<string, CompileError> {
  const trimmed = input.trim();
  if (trimmed === "") {
    return new Ok(RETURN + "0");
  }

  // Strip type annotations like ": U8" from variable declarations without regex
  let processed = "";
  let idx = 0;
  while (idx < trimmed.length) {
    const colonIdx = trimmed.indexOf(" : ", idx);
    if (colonIdx === -1) {
      processed += trimmed.substring(idx);
      break;
    } else {
      processed += trimmed.substring(idx, colonIdx);
      // Skip past the type name: starts with uppercase letter after " : "
      const typeStart = colonIdx + 3;
      idx = typeStart;
      while (idx < trimmed.length && !isWhitespace(trimmed[idx])) {
        idx++;
      }
    }
  }

  // Replace each read<U8>() with Number(tokens[i++])
  let output = "";
  let remaining = processed;
  while (remaining.length > 0) {
    const matchIndex = remaining.indexOf("read<U8>()");
    if (matchIndex === -1) {
      output += remaining;
      break;
    } else {
      output += remaining.substring(0, matchIndex);
      output += "Number(" + T + "[i++])";
      remaining = remaining.substring(matchIndex + 10); // length of "read<U8>()" is 10
    }
  }

  const hasTrailingSemicolon = output.endsWith(";");

  return new Ok(
    "const " + T + " = stdIn.trim().split(' '); let i = 0;" + (hasTrailingSemicolon ? output : RETURN + output) + RETURN_ZERO,
  );
}

"}

